import React, { useState, useEffect } from 'react';
import './Registration.css';

function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    service: 'Web Development',
    transactionId: '',
    message: ''
  });

  const [price, setPrice] = useState(0);

  // Dynamic pricing based on selected service
  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.service]);
  }, [formData.service]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Submission Data:", formData);
    alert(`Success! Your request for ${formData.service} has been submitted for verification.`);
  };

  return (
    <div className="register-page bg-light py-5">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-7">
            <div className="card shadow-lg border-0 p-4">
              <div className="card-body">
                <h2 className="fw-bold text-center mb-2 text-primary">Service Registration</h2>
                <p className="text-center text-muted mb-4">Complete the form and payment to get started.</p>
                
                <form onSubmit={handleSubmit}>
                  {/* Basic Info */}
                  <div className="row">
                    <div className="col-md-6 mb-3">
                      <label className="form-label fw-bold">Full Name</label>
                      <input type="text" name="name" className="form-control" placeholder="John Doe" required onChange={handleChange} />
                    </div>
                    <div className="col-md-6 mb-3">
                      <label className="form-label fw-bold">Email Address</label>
                      <input type="email" name="email" className="form-control" placeholder="john@example.com" required onChange={handleChange} />
                    </div>
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold">Select Service</label>
                    <select name="service" className="form-select" onChange={handleChange} value={formData.service}>
                      <option value="Web Development">Web Development</option>
                      <option value="UI/UX Design">UI/UX Design</option>
                      <option value="App Development">App Development</option>
                      <option value="Assignment Support">Assignment Support</option>
                      <option value="PPT Design">PPT Design</option>
                      <option value="Report Writing">Report Writing</option>
                    </select>
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold">Project Requirements</label>
                    <textarea name="message" className="form-control" rows="3" placeholder="Tell me about your project..." onChange={handleChange}></textarea>
                  </div>

                  {/* Payment Section */}
                  <div className="payment-box border rounded p-4 mt-4 bg-white">
                    <h5 className="fw-bold mb-3 border-bottom pb-2">Payment Details</h5>
                    
                    <div className="d-flex justify-content-between align-items-center mb-4 p-2 bg-light rounded">
                      <span className="text-secondary">Estimated Charges:</span>
                      <span className="fw-bold fs-4 text-dark">₹{price}</span>
                    </div>

                    <div className="row align-items-center">
                      <div className="col-sm-5 text-center border-end">
                        <p className="small fw-bold mb-2">Scan QR to Pay</p>
                        {/* Replace YOUR_UPI_ID with your actual ID */}
                        <img 
                          src={`https://api.qrserver.com{price}&tn=ServicePayment`} 
                          alt="Payment QR" 
                          className="img-fluid rounded border p-1 shadow-sm"
                        />
                      </div>
                      
                      <div className="col-sm-7 ps-md-4 mt-3 mt-md-0">
                        <label className="form-label small fw-bold text-danger">Transaction ID *</label>
                        <input 
                          type="text" 
                          name="transactionId" 
                          className="form-control mb-3" 
                          placeholder="Enter Reference Number" 
                          required 
                          onChange={handleChange} 
                        />
                        <div className="payment-methods">
                          <p className="extra-small text-muted mb-1 font-italic">Supported Apps:</p>
                          <span className="badge bg-light text-dark border me-1">GPay</span>
                          <span className="badge bg-light text-dark border me-1">PhonePe</span>
                          <span className="badge bg-light text-dark border">Paytm</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  <button type="submit" className="btn btn-primary w-100 fw-bold py-3 mt-4 text-uppercase">
                    Submit & Confirm Booking
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
